 *
 * Example configuration line format:
 * "cpu_model=Intel Xeon E5-2680,memory_mb=8192,disk_path=/var/vm/disk.img,network_adapter=virtio"
 *
 * @param config_line The configuration line string to parse, containing virtual machine hardware parameters
 * @param hw_config The hardware configuration structure to store parsed results; caller must pre-allocate memory
 *
 * @return Returns 0 on successful parsing, -1 on failure (e.g., malformed configuration line, missing parameters,
 *         parameter values exceeding buffer sizes, etc.). Passing an empty string also returns -1.
 */
int parse_vm_config(const char* config_line, struct vm_hardware_config* hw_config);

#endif /* VM_CONFIG_PARSER_H */
